// AXIOM Follow-Up Enforcer
// Automatically enforces follow-up sequences for all open leads

const now = new Date();
const followUps = [
  { leadId: 'LEAD-001', stage: 'Proposal Sent', daysSince: 1, action: 'Send follow-up #1' },
  { leadId: 'LEAD-002', stage: 'Contacted', daysSince: 3, action: 'Send value-add message' },
  { leadId: 'LEAD-003', stage: 'Proposal Sent', daysSince: 7, action: 'Create urgency message' }
];

const dueFollowUps = followUps.filter(f => f.daysSince >= 1);

return dueFollowUps.map(f => ({
  json: {
    ...f,
    timestamp: now.toISOString(),
    status: 'follow-up-triggered',
    message: `AXIOM FOLLOW-UP: ${f.action} for ${f.leadId}`
  }
}));
